use soroban_sdk::{contract, contractimpl, Address, Env, Bytes, Symbol};

#[contractimpl]
impl SafeAdminContract {
    // SAFE: upgrade with require_auth
    pub fn upgrade(env: Env, admin: Address, new_wasm: Bytes) {
        admin.require_auth();
        env.deployer().upload_contract_wasm(&new_wasm);
    }

    // SAFE: mint with require_auth via admin check
    pub fn safe_mint(env: Env, admin: Address, to: Address, amount: i128) {
        admin.require_auth();
        env.storage().instance().set(&to, &amount);
    }

    // SAFE: transfer_admin with only_admin
    pub fn transfer_admin(env: Env, caller: Address, new_admin: Address) {
        only_admin(&env, &caller);
        env.storage().instance().set(&Symbol::new(&env, "admin"), &new_admin);
    }

    // SAFE: unpause with assert_owner
    pub fn safe_unpause(env: Env, owner: Address) {
        assert_owner(&env, &owner);
        env.storage().instance().set(&Symbol::new(&env, "paused"), &false);
    }

    // SAFE: regular function (no privileged pattern)
    pub fn get_balance(env: Env, address: Address) -> i128 {
        env.storage().instance().get(&address).unwrap_or(0)
    }
}
